#include<iostream>
using namespace std;
bool f(int x){
	for(int i=2;i<x;i++){
		if(x%i==0){
			return 0;
		}
	}
	return 1;
}
long long ans[1005];
int main()
{
	int n;
	cin>>n;
	ans[0]=1;
	for(int i=2;i<=n;i++){
		if(!f(i)){
			continue;
		}
		for(int j=0;j<=n;j++){
			if(ans[j]&&j+i<=n){
				ans[j+i]+=ans[j];
			}
		}
	}
	cout<<ans[n];
}
